import React, { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Cookies from "js-cookie";
import dayjs from "dayjs";
import { toast } from "react-toastify";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function UserDetails() {
  const { userId } = useParams();
  const navigate = useNavigate();

  const [user, setUser] = useState(null);
  const [payments, setPayments] = useState([]);
  const [activeTab, setActiveTab] = useState("profile");
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) return navigate("/");

    setLoading(true);

    // Get user
    axios
      .get(`${API_BASE_URL}/users/${userId}`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setUser(res.data.data);
      })
      .catch(() => toast.error("Failed to load user"));

    // Get payments
    axios
      .get(`${API_BASE_URL}/users/${userId}/payments`, {
        headers: { Authorization: `Bearer ${token}` },
      })
      .then((res) => {
        if (res.data.success) setPayments(res.data.data);
      })
      .catch(() => toast.error("Failed to load payments"))
      .finally(() => setLoading(false));
  }, [userId, navigate]);

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (!user) return <div className="text-center mt-5">No user found</div>;

  // ================= Calculations =================
  const totalPaid = payments.reduce(
    (sum, p) => sum + Number(p.paidAmount || 0),
    0
  );

  const last12MonthsPaid = payments
    .filter((p) =>
      dayjs(p.paymentDate).isAfter(dayjs().subtract(12, "month"))
    )
    .reduce((sum, p) => sum + Number(p.paidAmount || 0), 0);

  return (
    <div className="container-fluid p-4">

      {/* =================== TOP SUMMARY =================== */}
      <div className="d-flex justify-content-between mb-4">
        <h4>User Profile</h4>
        <div>
          <strong>Total Paid :</strong> {totalPaid.toLocaleString()} &nbsp;&nbsp;
          <strong>Last 12 Months Payment :</strong>{" "}
          {last12MonthsPaid.toLocaleString()} &nbsp;&nbsp;
          <strong>Recurring Active :</strong> ❌
        </div>
      </div>

      {/* =================== USER INFO CARD =================== */}
      <div className="card p-3 mb-4 shadow-sm">
        <div className="row">
          <div className="col-md-2">
            <small>Name</small>
            <div>{user.prefix} {user.fullName}</div>
          </div>
          <div className="col-md-2">
            <small>Mobile No.</small>
            <div>{user.phone}</div>
          </div>
          <div className="col-md-3">
            <small>Email</small>
            <div>{user.email}</div>
          </div>
          <div className="col-md-2">
            <small>Relationship Manager</small>
            <div>{user.employeeName || "-"}</div>
          </div>
          <div className="col-md-2">
            <small>Risk Profile</small>
            <div className="badge bg-success">Aggressive</div>
          </div>
          <div className="col-md-1">
            <small>KYC</small>
            <div className="text-success">Completed</div>
          </div>
        </div>
      </div>

      {/* =================== TABS =================== */}
      <div className="mb-4 border-bottom">
        <div
          className="d-flex overflow-auto"
          style={{ whiteSpace: "nowrap" }}
        >
          {[
            { key: "profile", label: "Profile" },
            { key: "payments", label: "Payments" },
            { key: "timeline", label: "Timeline" },
            { key: "documents", label: "Documents" },
          ].map((tab) => (
            <button
              key={tab.key}
              className={`btn me-3 ${
                activeTab === tab.key
                  ? "btn-primary"
                  : "btn-outline-primary"
              }`}
              onClick={() => setActiveTab(tab.key)}
            >
              {tab.label}
            </button>
          ))}
        </div>
      </div>

      {/* =================== TAB CONTENT =================== */}

      {activeTab === "profile" && (
        <div className="card p-4 shadow-sm">
          <h5>User Details</h5>
          <div className="row mt-3">
            <div className="col-md-3">
              <label>Date of Birth</label>
              <input
                className="form-control"
                value={dayjs(user.createdAt).format("DD-MM-YYYY")}
                readOnly
              />
            </div>

            <div className="col-md-3">
              <label>User Status</label>
              <input
                className="form-control"
                value={user.status}
                readOnly
              />
            </div>
          </div>
        </div>
      )}

      {activeTab === "payments" && (
        <div className="card p-4 shadow-sm">
          <h5>Payments</h5>

          {payments.length > 0 ? (
            <div className="table-responsive mt-3">
              <table className="table table-bordered">
                <thead className="table-dark">
                  <tr>
                    <th>ID</th>
                    <th>Amount</th>
                    <th>Paid</th>
                    <th>Remaining</th>
                    <th>Status</th>
                    <th>Date</th>
                  </tr>
                </thead>
                <tbody>
                  {payments.map((p) => (
                    <tr key={p.id}>
                      <td>{p.id}</td>
                      <td>{p.totalAmount}</td>
                      <td>{p.paidAmount}</td>
                      <td>{p.remainingAmount}</td>
                      <td>{p.status}</td>
                      <td>
                        {dayjs(p.paymentDate).format(
                          "DD MMM YYYY, hh:mm A"
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : (
            <p>No payments found.</p>
          )}
        </div>
      )}

      {activeTab === "timeline" && (
        <div className="card p-4 shadow-sm">
          <h5>Timeline</h5>
          <p>Coming soon...</p>
        </div>
      )}

      {activeTab === "documents" && (
        <div className="card p-4 shadow-sm">
          <h5>Documents</h5>
          <p>Coming soon...</p>
        </div>
      )}
    </div>
  );
}

export default UserDetails;
